\u56F3\u306F\u30014P\u306E\u5404\u9805\u76EE\u304C4C\u306E\u5404\u9805\u76EE\u306B1\u5BFE1\u3067\u5BFE\u5FDC\u3059\u308B\u3053\u3068\u3092\u793A\u3057\u3066\u304A\u308A\u3001\u5BFE\u5FDC\u95A2\u4FC2\u306F\u6B21\u306E\u3068\u304A\u308A\u3067\u3042\u308B\u3002
